import ast

def evalInput(inputStr):
    try:
        node = ast.parse(inputStr, mode='eval')
        if not isinstance(node.body, ast.Expression):
            raise ValueError("Invalid expression")
        return eval(inputStr, {'__builtins__': {}}, {})
    except:
        return None

